import java.util.*;class CountingSort{public static void main(String[] a){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] x=new int[n];int max=0;for(int i=0;i<n;i++){x[i]=s.nextInt();if(x[i]>max)max=x[i];}int[] c=new int[max+1];for(int i=0;i<n;i++)c[x[i]]++;for(int i=1;i<=max;i++)c[i]+=c[i-1];int[] o=new int[n];for(int i=n-1;i>=0;i--){o[c[x[i]]-1]=x[i];c[x[i]]--;}for(int i=0;i<n;i++)System.out.print(o[i]+" ");}}